let base = Resources | where subscriptionId in ({Subscription});
let productHostCount = toscalar(base | where type in~ ('microsoft.web/sites', 'microsoft.app/containerapps', 'microsoft.containerservice/managedclusters', 'microsoft.solutions/applications', 'microsoft.solutions/applicationdefinitions') | count);
let endpointCount = toscalar(base | where type in~ ('microsoft.apimanagement/service', 'microsoft.logic/workflows', 'microsoft.app/containerapps') or (type =~ 'microsoft.web/sites' and kind has 'functionapp') | count);
let observabilityCount = toscalar(base | where type in~ ('microsoft.insights/components', 'microsoft.operationalinsights/workspaces') | count);
let keyVaultCount = toscalar(base | where type =~ 'microsoft.keyvault/vaults' | count);
let managedIdentityCount = toscalar(base | where isnotempty(tostring(identity.type)) | count);
let backboneCount = toscalar(base | where type in~ ('microsoft.servicebus/namespaces', 'microsoft.eventgrid/systemtopics', 'microsoft.storage/storageaccounts', 'microsoft.sql/servers/databases', 'microsoft.documentdb/databaseaccounts') | count);
let checks = union
(print Check = 'Offer surface', Weight = 25, Passed = productHostCount > 0),
(print Check = 'Provisioning or integration endpoint plane', Weight = 20, Passed = endpointCount > 0),
(print Check = 'Observability', Weight = 20, Passed = observabilityCount > 0),
(print Check = 'Secrets and workload identity', Weight = 20, Passed = keyVaultCount > 0 and managedIdentityCount > 0),
(print Check = 'Async backbone or durable state', Weight = 15, Passed = backboneCount > 0)
| extend PointsAwarded = iff(Passed, Weight, 0);
checks
| summarize ReadinessScore = sum(PointsAwarded), TotalPossible = sum(Weight), PassedChecks = countif(Passed), MissingChecks = countif(not(Passed))
| extend ScorePercent = round(100.0 * todouble(ReadinessScore) / todouble(TotalPossible), 1)
| extend ProductHosts = productHostCount, IntegrationEndpoints = endpointCount, ObservabilityAssets = observabilityCount, KeyVaults = keyVaultCount, IdentityEnabledResources = managedIdentityCount, BackboneResources = backboneCount

let base = Resources | where subscriptionId in ({Subscription});
let productHostCount = toscalar(base | where type in~ ('microsoft.web/sites', 'microsoft.app/containerapps', 'microsoft.containerservice/managedclusters', 'microsoft.solutions/applications', 'microsoft.solutions/applicationdefinitions') | count);
let endpointCount = toscalar(base | where type in~ ('microsoft.apimanagement/service', 'microsoft.logic/workflows', 'microsoft.app/containerapps') or (type =~ 'microsoft.web/sites' and kind has 'functionapp') | count);
let observabilityCount = toscalar(base | where type in~ ('microsoft.insights/components', 'microsoft.operationalinsights/workspaces') | count);
let keyVaultCount = toscalar(base | where type =~ 'microsoft.keyvault/vaults' | count);
let managedIdentityCount = toscalar(base | where isnotempty(tostring(identity.type)) | count);
let backboneCount = toscalar(base | where type in~ ('microsoft.servicebus/namespaces', 'microsoft.eventgrid/systemtopics', 'microsoft.storage/storageaccounts', 'microsoft.sql/servers/databases', 'microsoft.documentdb/databaseaccounts') | count);
union
(print Status = iff(productHostCount > 0, 'Passed', 'Missing')),
(print Status = iff(endpointCount > 0, 'Passed', 'Missing')),
(print Status = iff(observabilityCount > 0, 'Passed', 'Missing')),
(print Status = iff(keyVaultCount > 0 and managedIdentityCount > 0, 'Passed', 'Missing')),
(print Status = iff(backboneCount > 0, 'Passed', 'Missing'))
| summarize Checks = count() by Status

let base = Resources | where subscriptionId in ({Subscription});
let managedAppAssets = toscalar(base | where type in~ ('microsoft.solutions/applications', 'microsoft.solutions/applicationdefinitions') | count);
let appHosts = toscalar(base | where type in~ ('microsoft.web/sites', 'microsoft.app/containerapps', 'microsoft.containerservice/managedclusters') | count);
let endpointCount = toscalar(base | where type in~ ('microsoft.apimanagement/service', 'microsoft.logic/workflows', 'microsoft.app/containerapps') or (type =~ 'microsoft.web/sites' and kind has 'functionapp') | count);
print RecommendedPath = case(managedAppAssets > 0, 'Azure Managed Application', appHosts > 0 and endpointCount > 0, 'SaaS or Container Offer', appHosts > 0, 'Listing plus implementation services', 'Build product surface first'), ManagedAppAssets = managedAppAssets, ApplicationHosts = appHosts, EndpointPlaneAssets = endpointCount, Rationale = case(managedAppAssets > 0, 'Managed application assets already exist in Azure.', appHosts > 0 and endpointCount > 0, 'An application host and an endpoint plane are both visible.', appHosts > 0, 'You appear to have a host, but not the supporting endpoint layer that most transactable offers need.', 'Azure does not currently expose a clear product surface in the selected subscriptions.')

let base = Resources | where subscriptionId in ({Subscription});
let productHostCount = toscalar(base | where type in~ ('microsoft.web/sites', 'microsoft.app/containerapps', 'microsoft.containerservice/managedclusters', 'microsoft.solutions/applications', 'microsoft.solutions/applicationdefinitions') | count);
let endpointCount = toscalar(base | where type in~ ('microsoft.apimanagement/service', 'microsoft.logic/workflows', 'microsoft.app/containerapps') or (type =~ 'microsoft.web/sites' and kind has 'functionapp') | count);
let observabilityCount = toscalar(base | where type in~ ('microsoft.insights/components', 'microsoft.operationalinsights/workspaces') | count);
let keyVaultCount = toscalar(base | where type =~ 'microsoft.keyvault/vaults' | count);
let managedIdentityCount = toscalar(base | where isnotempty(tostring(identity.type)) | count);
let backboneCount = toscalar(base | where type in~ ('microsoft.servicebus/namespaces', 'microsoft.eventgrid/systemtopics', 'microsoft.storage/storageaccounts', 'microsoft.sql/servers/databases', 'microsoft.documentdb/databaseaccounts') | count);
union
(print Check = 'Offer surface', Status = iff(productHostCount > 0, 'Passed', 'Missing'), Weight = 25, Evidence = strcat(productHostCount, ' candidate hosts found'), WhyItMatters = 'Marketplace motion starts with a workload Azure can actually observe and deploy around.', RecommendedAction = 'Identify the specific app, container, cluster, or managed application you want to package.'),
(print Check = 'Provisioning or integration endpoint plane', Status = iff(endpointCount > 0, 'Passed', 'Missing'), Weight = 20, Evidence = strcat(endpointCount, ' endpoint resources found'), WhyItMatters = 'Transactable offers usually need some externally reachable plane for provisioning, webhook handling, or integration orchestration.', RecommendedAction = 'Add API Management, Function Apps, Logic Apps, or Container Apps to handle provisioning and fulfillment workflows.'),
(print Check = 'Observability', Status = iff(observabilityCount > 0, 'Passed', 'Missing'), Weight = 20, Evidence = strcat(observabilityCount, ' observability resources found'), WhyItMatters = 'Operational visibility is expected internally and during technical review.', RecommendedAction = 'Add Application Insights or Log Analytics and wire workload telemetry into it.'),
(print Check = 'Secrets and workload identity', Status = iff(keyVaultCount > 0 and managedIdentityCount > 0, 'Passed', 'Missing'), Weight = 20, Evidence = strcat(keyVaultCount, ' key vaults, ', managedIdentityCount, ' identity-enabled resources'), WhyItMatters = 'A transactable product should not depend on hard-coded credentials or weak secret handling.', RecommendedAction = 'Use managed identity on the workload and move secrets into Key Vault.'),
(print Check = 'Async backbone or durable state', Status = iff(backboneCount > 0, 'Passed', 'Missing'), Weight = 15, Evidence = strcat(backboneCount, ' backbone resources found'), WhyItMatters = 'Provisioning, plan changes, and customer lifecycle events usually need state or asynchronous processing.', RecommendedAction = 'Add storage, Service Bus, Event Grid, SQL, or Cosmos DB to support durable workflows.')
| extend PointsAwarded = iff(Status == 'Passed', Weight, 0)
| order by Status asc, Weight desc
